// ksaDataService.js
// Core data service: fetches JSON.txt static files generated by convert_mdb_to_json.py
// and delivers structured objects to AJAX callbacks via _trackAndInvoke.
//
// Dependencies (must be loaded before this file):
//   helpFuncs.js  — provides handleError()
//   ksaGlobals.js — provides KSA_UI_STATE.dataLoadQueue

// Wrap in an IIFE so internal helpers stay private; expose only the public API.
const KSA_DATA_SERVICE = (function () {
  'use strict';

  // ===========================================================================
  // CONSTANTS
  // ===========================================================================

  // Root-relative path to the JSON.txt file tree generated by convert_mdb_to_json.py.
  const DATABASE_ROOT = 'database/';

  // ===========================================================================
  // CACHE MAPS
  // ===========================================================================

  // Index cache: Map<entityId, indexObject>
  // indexObject keys are recordset folder names, values are sorted UT arrays.
  // e.g. { craftdata: [0, 28800], flightdata: [0, 28800, 57600], ... }
  const _indexCache = new Map();

  // Response cache: Map<url, parsedData>
  // Covers both UT-split record objects and bulk array files.
  // Keyed by the canonical URL (without cache-bust query string).
  const _responseCache = new Map();

  // In-flight deduplicator: Map<url, Promise<parsedData>>
  // Prevents duplicate concurrent fetch() calls for the same file.
  const _inFlight = new Map();

  // ===========================================================================
  // PRIVATE HELPERS
  // ===========================================================================

  // Returns "YYYY-MM-DD" so same-day requests share the browser cache but the
  // cache refreshes automatically the following day (mirrors loadJsonTxt behaviour).
  function _dateBust() {
    return new Date().toISOString().split('T')[0];
  }

  // ===========================================================================
  // PUBLIC API — CORE DATA UTILITIES
  // ===========================================================================

  /**
   * seekToUT(utArray, targetUT)
   *
   * Binary search: returns the largest UT value in a sorted ascending array that
   * is <= targetUT.  Replicates the ASP MoveLast/MovePrevious loop used across
   * all UT-seeking endpoints.
   *
   * If every element is > targetUT the first element is returned (mirrors ASP
   * behaviour where MovePrevious past BOF calls MoveNext back to first record).
   *
   * @param {number[]} utArray   Sorted ascending array of UT timestamps.
   * @param {number}   targetUT  The game-time UT to search for.
   * @returns {number|null}      Matching UT, or null if the array is empty.
   */
  function seekToUT(utArray, targetUT) {
    if (!utArray || !utArray.length) return null;
    var lo = 0, hi = utArray.length - 1, result = utArray[0];
    while (lo <= hi) {
      var mid = (lo + hi) >>> 1;
      if (utArray[mid] <= targetUT) {
        result = utArray[mid];
        lo = mid + 1;
      } else {
        hi = mid - 1;
      }
    }
    return result;
  }

  /**
   * getNextUT(utArray, targetUT)
   *
   * Binary search: returns the smallest UT value in a sorted ascending array
   * that is strictly > targetUT.  Used to pre-cache the next record boundary
   * (the "future data" the ASP endpoints also read ahead for).
   *
   * @param {number[]} utArray   Sorted ascending array of UT timestamps.
   * @param {number}   targetUT  The current game-time UT.
   * @returns {number|null}      The next UT after targetUT, or null if there are none.
   */
  function getNextUT(utArray, targetUT) {
    if (!utArray || !utArray.length) return null;
    var lo = 0, hi = utArray.length - 1, result = null;
    while (lo <= hi) {
      var mid = (lo + hi) >>> 1;
      if (utArray[mid] > targetUT) {
        result = utArray[mid];
        hi = mid - 1;
      } else {
        lo = mid + 1;
      }
    }
    return result;
  }

  /**
   * fetchJson(url)
   *
   * fetch() + JSON.parse() wrapper with:
   *   - Response caching  (no re-download for the lifetime of the page)
   *   - In-flight deduplication (concurrent callers share one pending fetch)
   *   - Date-based cache-busting (daily cache refresh; same-day requests reuse
   *     the browser HTTP cache — identical to loadJsonTxt's strategy)
   *
   * NOTE: loadJsonTxt() is intentionally reserved for the multi-object social
   * archive format; this function is used for all database JSON.txt files.
   *
   * @param {string} url  Relative or absolute path to the .json.txt file.
   * @returns {Promise}   Resolves to the parsed JSON value (object, array, …).
   */
  function fetchJson(url) {
    // Serve from in-memory cache on repeated calls.
    if (_responseCache.has(url)) {
      return Promise.resolve(_responseCache.get(url));
    }
    // Return the existing promise if a fetch is already in progress.
    if (_inFlight.has(url)) {
      return _inFlight.get(url);
    }

    var sep = url.indexOf('?') !== -1 ? '&' : '?';
    var fullUrl = url + sep + '_=' + _dateBust();

    var promise = fetch(fullUrl)
      .then(function (resp) {
        if (!resp.ok) {
          throw new Error('HTTP ' + resp.status + ' loading: ' + url);
        }
        return resp.text();
      })
      .then(function (text) {
        var data = JSON.parse(text);
        _responseCache.set(url, data);
        _inFlight.delete(url);
        return data;
      })
      ['catch'](function (err) {        // bracket notation avoids IE8 reserved-word parse error
        _inFlight.delete(url);
        throw err;
      });

    _inFlight.set(url, promise);
    return promise;
  }

  /**
   * _trackAndInvoke(label, callback, result, data)
   *
   * Manages KSA_UI_STATE.dataLoadQueue and delivers a structured result object
   * directly to the callback — no mock xhttp, no responseText parsing.
   *
   * Callback signature:
   *   callback(result, data)   // result = structured JS object, data = pass-through
   *
   * @param {string}   label     Descriptive label pushed onto dataLoadQueue.
   * @param {function} callback  AJAX callback (receives (result, data)).
   * @param {*}        result    Structured JS object produced by the fetch* function.
   * @param {*}        [data]    Optional pass-through value.
   */
  function _trackAndInvoke(label, callback, result, data) {
    KSA_UI_STATE.dataLoadQueue.push(label);
    console.log('[KSA_DATA_SERVICE]', label);
    // Remove the label from the queue, then invoke the callback.
    // then invoke the callback synchronously with the result object.
    var idx = KSA_UI_STATE.dataLoadQueue.indexOf(label);
    if (idx > -1) KSA_UI_STATE.dataLoadQueue.splice(idx, 1);
    try {
      callback(result, data);
    } catch (err) {
      handleError(err, label, true);
    }
  }

  // ===========================================================================
  // PUBLIC API — PATH HELPERS
  // ===========================================================================

  /**
   * indexPath(entityId)
   * URL to the index file for a craft or kerbal entity.
   * e.g. indexPath('jeb') → 'database/jeb/jeb_index.json.txt'
   */
  function indexPath(entityId) {
    return DATABASE_ROOT + entityId + '/' + entityId + '_index.json.txt';
  }

  /**
   * dbFilePath(entityId, recordset, ut)
   * URL to a specific UT-split record file.
   * e.g. dbFilePath('jeb', 'stats', 12345) → 'database/jeb/stats/jeb_stats_12345.json.txt'
   */
  function dbFilePath(entityId, recordset, ut) {
    return DATABASE_ROOT + entityId + '/' + recordset + '/' +
           entityId + '_' + recordset + '_' + ut + '.json.txt';
  }

  /**
   * bulkFilePath(entityId, recordset)
   * URL to a bulk (non-UT-split) data file loaded all at once.
   * e.g. bulkFilePath('jeb', 'missions') → 'database/jeb/jeb_missions.json.txt'
   */
  function bulkFilePath(entityId, recordset) {
    return DATABASE_ROOT + entityId + '/' + entityId + '_' + recordset + '.json.txt';
  }

  /**
   * catalogFilePath(name)
   * URL to a _Catalogs file.
   * e.g. catalogFilePath('bodies') → 'database/_Catalogs/bodies.json.txt'
   */
  function catalogFilePath(name) {
    return DATABASE_ROOT + '_Catalogs/' + name + '.json.txt';
  }

  /**
   * flightFilePath(flightId, recordset)
   * URL to a _Flights data file (dbFlt* databases).
   * e.g. flightFilePath('someFlight', 'missiondata')
   *        → 'database/_Flights/someFlight/someFlight_missiondata.json.txt'
   */
  function flightFilePath(flightId, recordset) {
    return DATABASE_ROOT + '_Flights/' + flightId + '/' +
           flightId + '_' + recordset + '.json.txt';
  }

  // ===========================================================================
  // PUBLIC API — INDEX MANAGEMENT
  // ===========================================================================

  /**
   * loadIndex(entityId)
   *
   * Loads and caches the index file for a craft or kerbal entity (once per page
   * load).  Subsequent calls for the same entityId are served from the index
   * cache with no network round-trip.
   *
   * The index object maps recordset folder names to sorted UT arrays:
   *   { craftdata: [0, 28800], flightdata: [0, 28800, 57600], ... }
   *
   * @param {string} entityId  Craft DB name or kerbal ID (lowercase).
   * @returns {Promise<Object>}
   */
  function loadIndex(entityId) {
    if (_indexCache.has(entityId)) {
      return Promise.resolve(_indexCache.get(entityId));
    }
    return fetchJson(indexPath(entityId)).then(function (index) {
      _indexCache.set(entityId, index);
      return index;
    });
  }

  // ===========================================================================
  // PRIVATE HELPERS
  // ===========================================================================

  /**
   * _normalizeStatsRecord(stats)
   *
   * Coerces Dockings and TEVA to proper integers.
   * Older DB exports serialized zero values as the string "0" rather than the
   * integer 0.  String "0" is truthy in JS, which would cause the conditional
   * display guards in ksaCrewOps.js to incorrectly show empty rows.
   * Operates in-place; safe to call with null/undefined.
   */
  function _normalizeStatsRecord(stats) {
    if (!stats) return;
    if (stats.Dockings !== null && stats.Dockings !== undefined) stats.Dockings = +stats.Dockings || 0;
    if (stats.TEVA     !== null && stats.TEVA     !== undefined) stats.TEVA     = +stats.TEVA     || 0;
  }

  /**
   * _normalizeKeys(obj)
   *
   * Returns a shallow copy of obj with all spaces removed from key names.
   * e.g. "Orbital Period" → "OrbitalPeriod", "SOI Event" → "SOIEvent".
   * Returns null/undefined unchanged.
   */
  function _normalizeKeys(obj) {
    if (!obj || typeof obj !== 'object') return obj;
    var normalized = {};
    Object.keys(obj).forEach(function (key) {
      normalized[key.replace(/ /g, '')] = obj[key];
    });
    return normalized;
  }

  // ===========================================================================
  // ENDPOINT IMPLEMENTATIONS
  // ===========================================================================

  // ---------------------------------------------------------------------------
  // Endpoint #1 — replaces loadBodyData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchBodyData(callback)
   *
   * Loads all planet and moon records from the merged bodies catalog and delivers
   * them to loadBodyAJAX as a native array of body objects.
   *
   * @param {function} callback  loadBodyAJAX — receives (bodies[]).
   */
  function fetchBodyData(callback) {
    var label = 'loadBodyData.asp';
    fetchJson(catalogFilePath('bodies'))
      .then(function(records) {
        _trackAndInvoke(label, callback, records);
      })
      ['catch'](function(err) {
        handleError(err, label, true);
      });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #2 — replaces loadPartsData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchPartsData(callback)
   *
   * Loads all parts records from the parts catalog and delivers them to
   * loadPartsAJAX as a native array of part objects.
   *
   * @param {function} callback  loadPartsAJAX — receives (parts[]).
   */
  function fetchPartsData(callback) {
    var label = 'loadPartsData.asp';
    fetchJson(catalogFilePath('parts'))
      .then(function(records) {
        _trackAndInvoke(label, callback, records);
      })
      ['catch'](function(err) {
        handleError(err, label, true);
      });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #3 — replaces loadAscentData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchAscentData(db, callback)
   *
   * Loads all rows from the ascent data bulk file for a given craft and delivers
   * them to the existing loadAscentAJAX callback in the same pipe-delimited
   * format that loadAscentData.asp produced.
   *
   * ASP logic replicated:
   *   - Dump all records from the [ascent data] table.
   *   - Apply replace(field.name, " ", "") to strip spaces from field names
   *     (the only affected field is "Total Fuel" → "TotalFuel").
   *   - Join records with "|" — no trailing "|" (loadAscentAJAX does not
   *     filter empty strings after splitting, so a trailing delimiter would
   *     push a spurious empty object into ops.ascentData.telemetry).
   *
   * The bulk file is cached after the first fetch so repeated calls (e.g.
   * if the user navigates away and back to the same vessel) are free.
   *
   * @param {string}   db        Craft DB name (e.g. "ascensionmk2-2").
   * @param {function} callback  Existing AJAX callback (loadAscentAJAX).
   */
  function fetchAscentData(db, callback) {
    var label = 'loadAscentData.asp?db=' + db;
    fetchJson(bulkFilePath(db, 'ascentdata'))
      .then(function (records) {
        // The "Total Fuel" column in the MDB contains a space in its name.
        // Normalize all keys by stripping spaces so consumers can read .TotalFuel.
        var normalized = records.map(function(obj) {
          var out = {};
          Object.keys(obj).forEach(function(k) { out[k.replace(/ /g, '')] = obj[k]; });
          return out;
        });
        _trackAndInvoke(label, callback, normalized);
      })
      ['catch'](function (err) {
        handleError(err, label, true);
      });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #4 — replaces loadMapData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchMapData(refID, callback)
   *
   * Loads map data from the JSON maps catalog and delivers a structured result
   * directly to the callback via _trackAndInvoke.
   *
   * Two modes:
   *   refID === -1  — result is the full records[] array (loadSurfaceUpdatesAJAX).
   *   refID number  — result is the single matching object, or null if not found
   *                   (loadMapDataAJAX).
   *
   * The maps catalog is fetched only once; the fetchJson cache serves
   * subsequent calls (per-body loads) with zero extra network round-trips.
   *
   * @param {number}   refID     -1 for all records, or the numeric body RefID.
   * @param {function} callback  loadSurfaceUpdatesAJAX (refID=-1) or
   *                             loadMapDataAJAX (specific body).
   *                             Receives (result) — a records[] or single object.
   */
  function fetchMapData(refID, callback) {
    var label = 'loadMapData.asp?refID=' + refID;

    // Fast path: if the startup call already cached the full catalog in
    // KSA_CATALOGS.mapCatalog, filter in-memory — no network or Promise overhead.
    if (refID !== -1 && KSA_CATALOGS.mapCatalog) {
      var cached = null;
      for (var i = 0; i < KSA_CATALOGS.mapCatalog.length; i++) {
        if (KSA_CATALOGS.mapCatalog[i].RefID === refID) { cached = KSA_CATALOGS.mapCatalog[i]; break; }
      }
      _trackAndInvoke(label, callback, cached);
      return;
    }

    fetchJson(catalogFilePath('maps'))
      .then(function (records) {
        var result;
        if (refID === -1) {
          result = (records && records.length) ? records : null;
        } else {
          result = null;
          for (var i = 0; i < records.length; i++) {
            if (records[i].RefID === refID) { result = records[i]; break; }
          }
        }
        _trackAndInvoke(label, callback, result);
      })
      ['catch'](function (err) {
        handleError(err, label, true);
      });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #5 — replaces loadFltData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchFltData(name, callback)
   *
   * Loads mission data (single record) and flight data (full array) for an
   * aircraft-type flight from the _Flights folder, then delivers a structured
   * result object directly to loadFltDataAJAX via _trackAndInvoke.
   *
   * Result shape: { mission: obj, flightData: sampledRows[], name: str }
   *
   * Flight data is sampled every 5th row (matching ASP's rsFlightData.move 5)
   * to limit memory usage for long flights. The full-resolution array is never
   * held in memory after the Promise resolves.
   *
   * Both files are cached by fetchJson() after the first load, so subsequent
   * calls for the same flight (e.g. multi-flight loads) are served from memory.
   *
   * @param {string}   name      Flight DB name (e.g. "Deuce1-22-19").
   * @param {function} callback  loadFltDataAJAX — receives (result).
   */
  function fetchFltData(name, callback) {
    var label = 'loadFltData.asp?data=' + name;
    Promise.all([
      fetchJson(flightFilePath(name, 'missiondata')),
      fetchJson(flightFilePath(name, 'flightdata'))
    ]).then(function (results) {
      var mission    = results[0];   // plain object (single-record table)
      var allRows    = results[1];   // array of all flight data records

      // Sample every 5th row, mirroring ASP's rsFlightData.move 5.
      var flightData = [];
      for (var i = 0; i < allRows.length; i += 5) {
        flightData.push(allRows[i]);
      }

      _trackAndInvoke(label, callback, { mission: mission, flightData: flightData, name: name });
    })
    ['catch'](function (err) {
      handleError(err, label, true);
    });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #6 — replaces loadMenuData.asp
  // ---------------------------------------------------------------------------

  /**
   * _buildMenuCraftRecord(vessel, ut)
   *
   * Private helper used only by fetchMenuData.
   * Reads pre-structured JSON fields (Phase 1 format) and returns a typed
   * vessel entry object for loadMenuAJAX, or null when ref === -2.
   *
   * start default (MissionStartTime is null): FIRST SOI entry ut.
   * end default   (MissionEnd is null):       LAST  SOI entry ut.
   * bodyRef: second-to-last SOI entry's ref (last non-inactive body reference).
   */
  function _buildMenuCraftRecord(vessel, ut) {
    // Determine current SOI ref from pre-structured array [{ut, ref}, ...].
    var soi = vessel.SOI;
    var ref = -2;
    for (var i = 0; i < soi.length; i++) {
      if (soi[i].ut <= ut) ref = soi[i].ref;
      else break;
    }

    // ref === -2 → vessel is completely removed from both menu lists.
    if (ref === -2) return null;

    // Derive default times from SOI array.
    var firstSoiUT = soi[0].ut;
    var lastSoiUT  = soi[soi.length - 1].ut;

    var start = (vessel.MissionStartTime !== null && vessel.MissionStartTime !== undefined)
      ? vessel.MissionStartTime
      : firstSoiUT;

    var end = (vessel.MissionEnd !== null && vessel.MissionEnd !== undefined)
      ? vessel.MissionEnd.utEnd
      : lastSoiUT;

    // Compute current name from pre-structured Vessel field.
    // If it's an array [{ut, name}], find the last entry whose ut <= current UT.
    // If it's a plain string, use it directly.
    var name, names;
    if (Array.isArray(vessel.Vessel)) {
      names = vessel.Vessel;
      name  = names[0].name;
      for (var ni = 0; ni < names.length; ni++) {
        if (names[ni].ut === null || names[ni].ut <= ut) name = names[ni].name;
        else break;
      }
    } else {
      name  = vessel.Vessel;
      names = null;
    }

    // Compute current type from pre-structured Type field (same pattern).
    var type;
    if (Array.isArray(vessel.Type)) {
      type = vessel.Type[0].type;
      for (var ti = 0; ti < vessel.Type.length; ti++) {
        if (vessel.Type[ti].ut === null || vessel.Type[ti].ut <= ut) type = vessel.Type[ti].type;
        else break;
      }
    } else {
      type = vessel.Type;
    }

    // bodyRef: second-to-last SOI entry's ref (the last body before going inactive).
    var bodyRef = 3;
    if (soi.length > 1) bodyRef = soi[soi.length - 2].ref;

    // Program and vessel-patch names from pre-structured Patches object.
    var program, vesselName;
    if (vessel.Patches !== null && vessel.Patches !== undefined) {
      program    = vessel.Patches.program.name;
      vesselName = vessel.Patches.vessel.name;
    } else {
      program    = null;
      vesselName = null;
    }

    return {
      db:       vessel.DB,
      name:     name,
      names:    names,
      soi:      soi,
      type:     type,
      start:    start,
      end:      end,
      program:  program,
      vessel:   vesselName,
      timeline: (vessel.Timeline !== null && vessel.Timeline !== undefined) ? vessel.Timeline : null,
      bodyRef:  bodyRef,
      desc:     vessel.Desc || null
    };
  }

  /**
   * fetchMenuData(ut, callback)
   *
   * Loads vessel and crew catalogs, UT-seeks each
   * crew member's stats record, and delivers a structured result object to
   * loadMenuAJAX via _trackAndInvoke (Phase 3 convention — no delimited strings).
   *
   * Result shape: { vessels: vesselEntry[], crew: crewEntry[] }
   *
   * vesselEntry keys (all pre-computed at fetch time):
   *   db, name, names, soi, type, start, end, program, vessel, timeline, bodyRef
   *
   * crewEntry keys:
   *   fullName, status, rank, assignment, db, ut, deactivation, timeline
   *
   * This is the primary startup-critical endpoint: after it resolves,
   * loadMenuAJAX bootstraps the sidebar and triggers loadOpsDataAJAX for
   * all active entities.  Catalogs and kerbal index files are cached by
   * fetchJson so they are free on subsequent calls.
   *
   * @param {number}   ut        Current game UT in seconds.
   * @param {function} callback  loadMenuAJAX — receives (result).
   */
  function fetchMenuData(ut, callback) {
    var label = 'loadMenuData.asp?UT=' + ut;

    Promise.all([
      fetchJson(catalogFilePath('vessels')),
      fetchJson(catalogFilePath('crew'))
    ]).then(function (catalogs) {
      var vesselCatalog = catalogs[0];
      var crewCatalog   = catalogs[1];

      // For each crew member: load JSON index → seekToUT in stats array → load stats.
      var crewPromises = crewCatalog.map(function (crewItem) {
        return fetchJson(indexPath(crewItem.Kerbal)).then(function (index) {
          var statsUT = seekToUT(index.stats, ut);
          return fetchJson(dbFilePath(crewItem.Kerbal, 'stats', statsUT))
            .then(function (statsRecord) {
              return { crewItem: crewItem, stats: statsRecord };
            });
        });
      });

      return Promise.all(crewPromises).then(function (crewResults) {
        return { vessels: vesselCatalog, crew: crewResults };
      });
    }).then(function (data) {

      // Build typed vessel entries — _buildMenuCraftRecord returns null for ref===-2.
      var vessels = [];
      data.vessels.forEach(function (vessel) {
        var entry = _buildMenuCraftRecord(vessel, ut);
        if (entry !== null) vessels.push(entry);
      });

      // Build typed crew entries.
      var crew = data.crew.map(function (result) {
        var c = result.crewItem;
        var s = result.stats;
        return {
          fullName:     c.FullName,
          status:       s.Status,
          rank:         s.Rank,
          assignment:   (s.Assignment !== null && s.Assignment !== undefined) ? s.Assignment : null,
          db:           c.Kerbal,
          ut:           s.UT,
          deactivation: c.Deactivation,
          timeline:     (c.Timeline !== null && c.Timeline !== undefined) ? c.Timeline : null
        };
      });

      _trackAndInvoke(label, callback, { vessels: vessels, crew: crew });
    })['catch'](function (err) {
      handleError(err, label, true);
    });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #7 — replaces loadEventData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchEventData(ut, callback)
   *
   * Scans all active, non-aircraft vessels for upcoming launch events and
   * planned maneuvers, then delivers a structured result to loadEventsAJAX
   * via _trackAndInvoke (Phase 3 convention — no delimited strings).
   *
   * Result shape: { launches: launchEntry[], maneuvers: maneuverEntry[] }
   *
   * launchEntry:   { UT, LaunchTime, db, Title, Desc }
   * maneuverEntry: { UT, ExecuteUT, db, Title, Desc }
   *
   * ASP logic preserved:
   *   - Iterate vessels catalog in catalog order (no sort — ASP's SortArray
   *     was defined but never called before output).
   *   - For each vessel, compute current SOI ref (last SOI entry UT <= ut).
   *     Default ref = -1 (vessel not yet active); skip if ref <= -1 or
   *     current type === 'aircraft'.
   *   - Load launch-times bulk file: one entry per row, LaunchTime null → 0.
   *   - Load index → seekToUT on flightplan array → load record: if
   *     ExecuteUT > ut, emit as a maneuver entry.
   *   - Maneuvers capped at the first two found (matching ASP two-slot output).
   *
   * The vessels catalog is already in _responseCache after fetchMenuData, so
   * that fetch is free.  Launch-times and index files are likewise cached,
   * making repeated calls (liftoff refresh, maneuver refresh) serve from memory.
   *
   * @param {number}   ut        Current game UT in seconds.
   * @param {function} callback  loadEventsAJAX — receives (result).
   */
  function fetchEventData(ut, callback) {
    var label = 'loadEventData.asp?UT=' + ut;

    fetchJson(catalogFilePath('vessels'))
      .then(function (vessels) {

        // Process all vessels concurrently, preserving catalog iteration order.
        var vesselPromises = vessels.map(function (vessel) {

          // Compute current SOI ref from pre-structured [{ut, ref}, ...] array.
          // Default -1 (vessel not yet active); differs from fetchMenuData
          // default 0 — intentional and correct here.
          var soi = vessel.SOI;
          var ref = -1;
          for (var i = 0; i < soi.length; i++) {
            if (soi[i].ut <= ut) ref = soi[i].ref;
            else break;
          }

          // Compute current type from pre-structured Type field (same pattern
          // as _buildMenuCraftRecord): plain string if single, array otherwise.
          var type;
          if (Array.isArray(vessel.Type)) {
            type = vessel.Type[0].type;
            for (var ti = 0; ti < vessel.Type.length; ti++) {
              if (vessel.Type[ti].ut === null || vessel.Type[ti].ut <= ut) type = vessel.Type[ti].type;
              else break;
            }
          } else {
            type = vessel.Type;
          }

          // Skip inactive (ref <= -1 covers -2) and aircraft.
          if (ref <= -1 || type === 'aircraft') {
            return Promise.resolve({ launches: [], flightplan: null });
          }

          // Compute current vessel name (same pattern as _buildMenuCraftRecord).
          var name;
          if (Array.isArray(vessel.Vessel)) {
            name = vessel.Vessel[0].name;
            for (var ni = 0; ni < vessel.Vessel.length; ni++) {
              if (vessel.Vessel[ni].ut === null || vessel.Vessel[ni].ut <= ut) name = vessel.Vessel[ni].name;
              else break;
            }
          } else {
            name = vessel.Vessel;
          }

          var db = vessel.DB;

          // Load launch times and index concurrently; errors treated as
          // "no data" so a missing file never aborts the whole response.
          var launchPromise = fetchJson(bulkFilePath(db, 'launchtimes'))
            ['catch'](function () { return []; });

          var flightplanPromise = fetchJson(indexPath(db))
            .then(function (index) {
              if (!index.flightplan || !index.flightplan.length) return null;
              var fpUT = seekToUT(index.flightplan, ut);
              if (fpUT === null) return null;
              return fetchJson(dbFilePath(db, 'flightplan', fpUT))
                ['catch'](function () { return null; });
            })
            ['catch'](function () { return null; });

          return Promise.all([launchPromise, flightplanPromise])
            .then(function (results) {
              var launchRows = results[0] || [];
              var fpRecord   = results[1];

              // Build typed launch entry objects; LaunchTime null → 0.
              var launchEntries = launchRows.map(function (row) {
                return {
                  UT:         row.UT,
                  LaunchTime: (row.LaunchTime !== null && row.LaunchTime !== undefined) ? row.LaunchTime : 0,
                  db:         db,
                  Title:      name,
                  Desc:       vessel.Desc
                };
              });

              // Flightplan entry: only if ExecuteUT is still in the future.
              var fpEntry = null;
              if (fpRecord && fpRecord.ExecuteUT > ut) {
                fpEntry = {
                  UT:        fpRecord.UT,
                  ExecuteUT: fpRecord.ExecuteUT,
                  db:        db,
                  Title:     name,
                  Desc:      fpRecord.Desc
                };
              }

              return { launches: launchEntries, flightplan: fpEntry };
            });
        });

        return Promise.all(vesselPromises);
      })
      .then(function (vesselResults) {

        // Collect in catalog-iteration order (no sort — matches ASP behavior).
        var allLaunches  = [];
        var allManeuvers = [];
        vesselResults.forEach(function (result) {
          result.launches.forEach(function (entry) { allLaunches.push(entry); });
          if (result.flightplan !== null) allManeuvers.push(result.flightplan);
        });

        _trackAndInvoke(label, callback, {
          launches:  allLaunches,
          maneuvers: allManeuvers.slice(0, 2)
        });
      })
      ['catch'](function (err) {
        handleError(err, label, true);
      });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #8 — replaces loadCrewData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchCrewData(db, ut, callback)
   *
   * Loads all data for a single crew member and delivers it to the existing
   * loadCrewAJAX callback in the same format that loadCrewData.asp produced.
   *
   * ASP logic replicated:
   *   Catalog section  — all fields from the Crew table for the given kerbal.
   *   Stats section    — UT-seek: largest UT <= current from [kerbal stats].
   *   Missions section — all mission rows with UT <= current, pipe-delimited;
   *                      "null" when empty or first row is in the future.
   *   Ribbons section  — same filter pattern as missions.
   *   Background section — UT-seek: largest UT <= current from [background].
   *   Future section   — next stats record, next mission, next ribbon, next
   *                      background (each "null" when none exists).
   *
   * The crew catalog is already cached in _responseCache after fetchMenuData
   * runs at startup, so that fetch is always a cache hit.  The kerbal index
   * is likewise cached after fetchMenuData pre-loaded it for the menu.
   *
   * Response format (separators):
   *   [catalog]*[stats]^[missions]^[ribbons]^[background]*
   *   [nextStats]^[nextMission]^[nextRibbon]^[nextBackground]
   *
   * @param {string}   db        Kerbal database ID (lowercase, e.g. "jeb").
   * @param {number}   ut        Current game UT in seconds.
   * @param {function} callback  Existing AJAX callback (loadCrewAJAX).
   */
  function fetchCrewData(db, ut, callback) {
    var label = 'loadCrewData.asp?db=' + db + '&ut=' + ut;

    // Catalog (cache hit after fetchMenuData), index, and bulk files in parallel.
    Promise.all([
      fetchJson(catalogFilePath('crew')),
      loadIndex(db),
      fetchJson(bulkFilePath(db, 'missions'))['catch'](function () { return []; }),
      fetchJson(bulkFilePath(db, 'ribbons'))['catch'](function () { return []; })
    ]).then(function (results) {
      var crewCatalog = results[0];
      var index       = results[1];
      var allMissions = results[2];
      var allRibbons  = results[3];

      // Locate this kerbal's catalog entry (compare against Kerbal field, not DB).
      var crewEntry = crewCatalog.find(function (c) { return c.Kerbal === db; });

      // UT-seek for current and next stats / background.
      var statsUT     = seekToUT(index.stats,      ut);
      var bgUT        = seekToUT(index.background, ut);
      var nextStatsUT = getNextUT(index.stats,      ut);
      var nextBgUT    = getNextUT(index.background, ut);

      // Fetch current + next stats and background files concurrently.
      return Promise.all([
        fetchJson(dbFilePath(db, 'stats',      statsUT)),
        fetchJson(dbFilePath(db, 'background', bgUT)),
        nextStatsUT !== null
          ? fetchJson(dbFilePath(db, 'stats', nextStatsUT))['catch'](function () { return null; })
          : Promise.resolve(null),
        nextBgUT !== null
          ? fetchJson(dbFilePath(db, 'background', nextBgUT))['catch'](function () { return null; })
          : Promise.resolve(null)
      ]).then(function (fetched) {
        return {
          crewEntry:   crewEntry,
          stats:       fetched[0],
          background:  fetched[1],
          nextStats:   fetched[2],
          nextBg:      fetched[3],
          allMissions: allMissions,
          allRibbons:  allRibbons
        };
      });
    }).then(function (d) {

      // Missions up to current UT, newest-first for loadCrewAJAX.
      var currentMissions = d.allMissions.filter(function (m) { return m.UT <= ut; });
      currentMissions.reverse();

      // Ribbons up to current UT (ascending order — matches display logic).
      var currentRibbons = d.allRibbons.filter(function (r) { return r.UT <= ut; });

      // Normalize integer fields that may be strings in older DB exports.
      _normalizeStatsRecord(d.stats);
      _normalizeStatsRecord(d.nextStats);

      // Next future records (first item past current UT).
      var nextMission = d.allMissions.find(function (m) { return m.UT > ut; }) || null;
      var nextRibbon  = d.allRibbons.find(function (r) { return r.UT > ut; }) || null;

      _trackAndInvoke(label, callback, {
        catalog:    d.crewEntry,
        stats:      d.stats,
        background: d.background,
        missions:   currentMissions,
        ribbons:    currentRibbons,
        next: {
          stats:      d.nextStats || null,
          mission:    nextMission,
          ribbon:     nextRibbon,
          background: d.nextBg || null
        }
      });
    })['catch'](function (err) {
      handleError(err, label, true);
    });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #9 — replaces loadVesselOrbitData.asp
  // ---------------------------------------------------------------------------
  /**
   * fetchVesselOrbitData(db, ut, callback, data)
   *
   * UT-seeks the flightdata and flightplan tables for a vessel and delivers
   * a structured result to addOrbitAJAX or loadVesselOrbitAJAX via
   * _trackAndInvoke (Phase 3 convention — no delimited strings).
   *
   * Result shape: { db, flightData: obj|null, flightPlan: obj|null }
   * Keys are normalized (spaces stripped) so field names like "Orbital Period"
   * become "OrbitalPeriod" for direct property access.
   *
   * Cache behaviour: fetchJson() caches by URL, so if fetchVesselData (#10)
   * already loaded the same index and flightdata file, this call is a cache
   * hit with zero network round-trips.
   *
   * @param {string}   db        Vessel DB name (e.g. "kerbin-II").
   * @param {number}   ut        Current game UT in seconds.
   * @param {function} callback  addOrbitAJAX or loadVesselOrbitAJAX.
   * @param {*}        [data]    Optional pass-through value (e.g. currObj for loadVesselOrbitAJAX).
   */
  function fetchVesselOrbitData(db, ut, callback, data) {
    var label = 'loadVesselOrbitData.asp?db=' + db + '&ut=' + ut;

    fetchJson(indexPath(db))
      ['catch'](function () { return {}; })   // missing index → all-null response
      .then(function (index) {

        // UT-seek each table; null when the table has no entries in the index.
        var fdUT = (index.flightdata && index.flightdata.length)
          ? seekToUT(index.flightdata, ut)
          : null;
        var fpUT = (index.flightplan && index.flightplan.length)
          ? seekToUT(index.flightplan, ut)
          : null;

        var fdPromise = fdUT !== null
          ? fetchJson(dbFilePath(db, 'flightdata', fdUT))['catch'](function () { return null; })
          : Promise.resolve(null);

        var fpPromise = fpUT !== null
          ? fetchJson(dbFilePath(db, 'flightplan', fpUT))['catch'](function () { return null; })
          : Promise.resolve(null);

        return Promise.all([fdPromise, fpPromise]);
      })
      .then(function (results) {
        _trackAndInvoke(label, callback, {
          db:         db,
          flightData: _normalizeKeys(results[0]),
          flightPlan: _normalizeKeys(results[1])
        }, data);
      })
      ['catch'](function (err) {
        handleError(err, label, true);
      });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #10 — replaces loadVesselData.asp
  // ---------------------------------------------------------------------------

  /**
   * fetchVesselData(db, ut, callback, data)
   *
   * Loads all data tables for a single vessel and delivers a structured result
   * object to loadVesselAJAX via _trackAndInvoke (Phase 3 convention).
   *
   * Result shape:
   *   {
   *     catalog:        <vessel catalog entry>,
   *     ascentRange:    [firstUT, lastUT] | null,
   *     current: {
   *       craft:     <craftdata record | null>,
   *       resources: <resources record + NotNull | null>,
   *       manifest:  <manifest record | null>,
   *       comms:     <comms record + NotNull; Comms is pre-structured array | null>,
   *       orbit:     <flightdata record with keys normalised (no spaces) | null>,
   *       ports:     <ports record | null>
   *     },
   *     history:        [{UT, Title}, ...],   // from compact craftdata_history file
   *     launchTimes:    [{UT, LaunchTime}, ...],
   *     orbitalHistory: [{UT, Period}, ...]   // from compact flightdata_history file
   *   }
   *
   * @param {string}   db        Vessel DB name (e.g. "ascensionmk2-2").
   * @param {number}   ut        Current game UT in seconds.
   * @param {function} callback  loadVesselAJAX — receives (result, data).
   * @param {*}        [data]    Optional pass-through value.
   */
  function fetchVesselData(db, ut, callback, data) {
    var label = 'loadVesselData.asp?db=' + db + '&ut=' + ut;

    Promise.all([
      fetchJson(catalogFilePath('vessels')),
      fetchJson(indexPath(db))['catch'](function () { return {}; }),
      fetchJson(bulkFilePath(db, 'ascentdata'))       ['catch'](function () { return []; }),
      fetchJson(bulkFilePath(db, 'launchtimes'))      ['catch'](function () { return []; }),
      fetchJson(bulkFilePath(db, 'craftdata_history'))['catch'](function () { return []; }),
      fetchJson(bulkFilePath(db, 'flightdata_history'))['catch'](function () { return []; })
    ]).then(function (step1) {
      var vesselCatalog  = step1[0];
      var index          = step1[1];
      var ascentRows     = step1[2];
      var launchRows     = step1[3];
      var craftHistory   = step1[4];
      var flightHistory  = step1[5];

      // Locate this vessel's catalog entry.
      var catalogEntry = null;
      for (var vi = 0; vi < vesselCatalog.length; vi++) {
        if (vesselCatalog[vi].DB === db) { catalogEntry = vesselCatalog[vi]; break; }
      }

      // UT-seek for each of the 6 current-record tables.
      var cdUT  = (index.craftdata  && index.craftdata.length)  ? seekToUT(index.craftdata,  ut) : null;
      var resUT = (index.resources  && index.resources.length)  ? seekToUT(index.resources,  ut) : null;
      var mnUT  = (index.manifest   && index.manifest.length)   ? seekToUT(index.manifest,   ut) : null;
      var cmUT  = (index.comms      && index.comms.length)      ? seekToUT(index.comms,      ut) : null;
      var fdUT  = (index.flightdata && index.flightdata.length) ? seekToUT(index.flightdata, ut) : null;
      var ptUT  = (index.ports      && index.ports.length)      ? seekToUT(index.ports,      ut) : null;
      // Future-guard: if all index UTs > targetUT, seekToUT returns utArray[0]; treat as null.
      if (cdUT  !== null && cdUT  > ut) cdUT  = null;
      if (resUT !== null && resUT > ut) resUT = null;
      if (mnUT  !== null && mnUT  > ut) mnUT  = null;
      if (cmUT  !== null && cmUT  > ut) cmUT  = null;
      if (fdUT  !== null && fdUT  > ut) fdUT  = null;
      if (ptUT  !== null && ptUT  > ut) ptUT  = null;

      return Promise.all([
        cdUT  !== null ? fetchJson(dbFilePath(db, 'craftdata',  cdUT)) ['catch'](function () { return null; }) : Promise.resolve(null),
        resUT !== null ? fetchJson(dbFilePath(db, 'resources',  resUT))['catch'](function () { return null; }) : Promise.resolve(null),
        mnUT  !== null ? fetchJson(dbFilePath(db, 'manifest',   mnUT)) ['catch'](function () { return null; }) : Promise.resolve(null),
        cmUT  !== null ? fetchJson(dbFilePath(db, 'comms',      cmUT)) ['catch'](function () { return null; }) : Promise.resolve(null),
        fdUT  !== null ? fetchJson(dbFilePath(db, 'flightdata', fdUT)) ['catch'](function () { return null; }) : Promise.resolve(null),
        ptUT  !== null ? fetchJson(dbFilePath(db, 'ports',      ptUT)) ['catch'](function () { return null; }) : Promise.resolve(null)
      ]).then(function (current) {
        return {
          catalogEntry:  catalogEntry,
          ascentRows:    ascentRows,
          launchRows:    launchRows,
          craftHistory:  craftHistory,
          flightHistory: flightHistory,
          craftRecord:   current[0],
          resRecord:     current[1],
          mnRecord:      current[2],
          cmRecord:      current[3],
          fdRecord:      current[4],
          ptRecord:      current[5]
        };
      });
    }).then(function (d) {

      // Ascent data range.
      var ascentRange = (d.ascentRows && d.ascentRows.length > 0)
        ? [d.ascentRows[0].UT, d.ascentRows[d.ascentRows.length - 1].UT]
        : null;

      // Resources: add NotNull — true if any non-UT field has a value.
      var resRecord = d.resRecord;
      if (resRecord) {
        var resNotNull = false;
        var resKeys = Object.keys(resRecord);
        for (var ri = 0; ri < resKeys.length; ri++) {
          var rk = resKeys[ri];
          if (rk !== 'UT' && resRecord[rk] !== null && resRecord[rk] !== undefined && resRecord[rk] !== '') {
            resNotNull = true; break;
          }
        }
        resRecord = Object.assign({}, resRecord, { NotNull: resNotNull });
      }

      // Comms: add NotNull — true if the Comms array is non-empty.
      var cmRecord = d.cmRecord;
      if (cmRecord) {
        var cmNotNull = !!(cmRecord.Comms && cmRecord.Comms.length > 0);
        cmRecord = Object.assign({}, cmRecord, { NotNull: cmNotNull });
      }

      // Orbit (flightdata): normalise keys to strip spaces
      // ("Avg Velocity" → "AvgVelocity", "Orbital Period" → "OrbitalPeriod", etc.).
      var orbitRecord = _normalizeKeys(d.fdRecord);

      // History: map CraftDescTitle → Title; sort ascending by UT.
      var history = (d.craftHistory || [])
        .filter(function (r) { return r !== null; })
        .sort(function (a, b) { return a.UT - b.UT; })
        .map(function (r) { return { UT: r.UT, Title: r.CraftDescTitle || '' }; });

      // Orbital history: map OrbitalPeriod → Period; sort ascending by UT.
      var orbitalHistory = (d.flightHistory || [])
        .filter(function (r) { return r !== null; })
        .sort(function (a, b) { return a.UT - b.UT; })
        .map(function (r) { return { UT: r.UT, Period: r.OrbitalPeriod }; });

      _trackAndInvoke(label, callback, {
        catalog:        d.catalogEntry,
        ascentRange:    ascentRange,
        current: {
          craft:     d.craftRecord,
          resources: resRecord,
          manifest:  d.mnRecord,
          comms:     cmRecord,
          orbit:     orbitRecord,
          ports:     d.ptRecord
        },
        history:        history,
        launchTimes:    d.launchRows || [],
        orbitalHistory: orbitalHistory
      }, data);
    })['catch'](function (err) {
      handleError(err, label, true);
    });
  }

  // ---------------------------------------------------------------------------
  // Endpoint #11 — replaces loadOpsData.asp
  // ---------------------------------------------------------------------------

  /**
   * fetchOpsData(db, ut, type, callback, data)
   *
   * Real-time update endpoint: loads current + next-future records for one
   * vessel or crew member and delivers a structured result to loadOpsDataAJAX
   * via _trackAndInvoke.
   *
   * Result shapes (produced by sub-functions):
   *   type="vessel" — { type, id, current: { CraftData, Resources, Manifest,
   *     Comms, Orbit, Ports } (UT-only), future: { same keys, full records } }
   *   type="crew"   — { type, id, current: { Stats, History (UT-only),
   *     Missions, Ribbons (full arrays) }, future: { Stats, History, Missions,
   *     Ribbons (single objects or null) } }
   *
   * Cache behaviour: index files, record files, and bulk files are shared
   * with fetchVesselData / fetchCrewData via _responseCache, so calls after
   * the initial load are served entirely from cache.
   *
   * @param {string}   db       Entity DB name (e.g. "kerbin-II" or "jeb").
   * @param {number}   ut       Current game UT in seconds.
   * @param {string}   type     "vessel" or "crew".
   * @param {function} callback loadOpsDataAJAX.
   * @param {*}        [data]   Optional pass-through value.
   */
  function fetchOpsData(db, ut, type, callback, data) {
    var label = 'loadOpsData.asp?db=' + db + '&UT=' + ut + '&type=' + type;
    // Queue management is handled by _trackAndInvoke inside the sub-functions.
    if (type === 'crew') {
      _fetchOpsCrewData(db, ut, label, callback, data);
    } else {
      _fetchOpsVesselData(db, ut, label, callback, data);
    }
  }

  /**
   * _fetchOpsCrewData — private: assembles the crew-path response for fetchOpsData.
   *
   * Result shape:
   *   { type: 'crew', id, current: { Stats, History, Missions, Ribbons },
   *     future: { Stats, History, Missions, Ribbons } }
   *
   * current.Stats / current.History carry only { UT } for badge-UT comparison.
   * current.Missions / current.Ribbons are full filtered arrays (for last-visit
   * badge counting). future values are single objects or null.
   */
  function _fetchOpsCrewData(db, ut, label, callback, data) {
    Promise.all([
      loadIndex(db),
      fetchJson(bulkFilePath(db, 'missions'))['catch'](function () { return []; }),
      fetchJson(bulkFilePath(db, 'ribbons'))['catch'](function () { return []; })
    ]).then(function (results) {
      var index       = results[0];
      var allMissions = results[1];
      var allRibbons  = results[2];

      var statsUT     = seekToUT(index.stats,      ut);
      var bgUT        = seekToUT(index.background, ut);
      var nextStatsUT = getNextUT(index.stats,      ut);
      var nextBgUT    = getNextUT(index.background, ut);

      return Promise.all([
        fetchJson(dbFilePath(db, 'stats',      statsUT)),
        fetchJson(dbFilePath(db, 'background', bgUT)),
        nextStatsUT !== null
          ? fetchJson(dbFilePath(db, 'stats', nextStatsUT))['catch'](function () { return null; })
          : Promise.resolve(null),
        nextBgUT !== null
          ? fetchJson(dbFilePath(db, 'background', nextBgUT))['catch'](function () { return null; })
          : Promise.resolve(null)
      ]).then(function (fetched) {
        return {
          stats:       fetched[0],
          background:  fetched[1],
          nextStats:   fetched[2],
          nextBg:      fetched[3],
          allMissions: allMissions,
          allRibbons:  allRibbons
        };
      });
    }).then(function (d) {
      _normalizeStatsRecord(d.stats);
      if (d.nextStats) _normalizeStatsRecord(d.nextStats);

      var currentMissions = d.allMissions.filter(function (m) { return m.UT <= ut; });
      currentMissions.reverse();
      var currentRibbons = d.allRibbons.filter(function (r) { return r.UT <= ut; });
      var nextMission    = d.allMissions.find(function (m) { return m.UT > ut; }) || null;
      var nextRibbon     = d.allRibbons.find(function (r) { return r.UT > ut; }) || null;

      _trackAndInvoke(label, callback, {
        type: 'crew',
        id:   db,
        current: {
          Stats:    { UT: d.stats.UT },
          History:  { UT: d.background.UT },
          Missions: currentMissions,
          Ribbons:  currentRibbons
        },
        future: {
          Stats:    d.nextStats || null,
          History:  d.nextBg    || null,
          Missions: nextMission,
          Ribbons:  nextRibbon
        }
      }, data);
    })['catch'](function (err) {
      var idx = KSA_UI_STATE.dataLoadQueue.indexOf(label);
      if (idx > -1) KSA_UI_STATE.dataLoadQueue.splice(idx, 1);
      handleError(err, label, true);
    });
  }

  /**
   * _fetchOpsVesselData — private: assembles the vessel-path response for fetchOpsData.
   *
   * Result shape:
   *   { type: 'vessel', id, current: { CraftData, Resources, Manifest, Comms, Orbit, Ports },
   *     future: { CraftData, Resources, Manifest, Comms, Orbit, Ports } }
   *
   * current values carry only { UT } for badge-UT comparison.
   * future values are full records (or null) so updateVesselData can copy them
   * into ops.currentVessel. Resources and Comms include a NotNull boolean.
   * Orbit (flightdata) keys are normalized to strip spaces.
   */
  function _fetchOpsVesselData(db, ut, label, callback, data) {
    Promise.all([
      fetchJson(catalogFilePath('vessels')),
      fetchJson(indexPath(db))['catch'](function () { return {}; })
    ]).then(function (step1) {
      var vesselCatalog = step1[0];
      var index         = step1[1];

      // UT-seek for current records.
      var cdUT  = (index.craftdata  && index.craftdata.length)  ? seekToUT(index.craftdata,  ut) : null;
      var resUT = (index.resources  && index.resources.length)  ? seekToUT(index.resources,  ut) : null;
      var mnUT  = (index.manifest   && index.manifest.length)   ? seekToUT(index.manifest,   ut) : null;
      var cmUT  = (index.comms      && index.comms.length)      ? seekToUT(index.comms,      ut) : null;
      var fdUT  = (index.flightdata && index.flightdata.length) ? seekToUT(index.flightdata, ut) : null;
      var ptUT  = (index.ports      && index.ports.length)      ? seekToUT(index.ports,      ut) : null;
      // Future-guard: null out UTs that are still in the future.
      if (cdUT  !== null && cdUT  > ut) cdUT  = null;
      if (resUT !== null && resUT > ut) resUT = null;
      if (mnUT  !== null && mnUT  > ut) mnUT  = null;
      if (cmUT  !== null && cmUT  > ut) cmUT  = null;
      if (fdUT  !== null && fdUT  > ut) fdUT  = null;
      if (ptUT  !== null && ptUT  > ut) ptUT  = null;

      // getNextUT for future records.
      var futCdUT  = (index.craftdata  && index.craftdata.length)  ? getNextUT(index.craftdata,  ut) : null;
      var futResUT = (index.resources  && index.resources.length)  ? getNextUT(index.resources,  ut) : null;
      var futMnUT  = (index.manifest   && index.manifest.length)   ? getNextUT(index.manifest,   ut) : null;
      var futCmUT  = (index.comms      && index.comms.length)      ? getNextUT(index.comms,      ut) : null;
      var futFdUT  = (index.flightdata && index.flightdata.length) ? getNextUT(index.flightdata, ut) : null;
      var futPtUT  = (index.ports      && index.ports.length)      ? getNextUT(index.ports,      ut) : null;

      return Promise.all([
        cdUT    !== null ? fetchJson(dbFilePath(db, 'craftdata',  cdUT))['catch'](function () { return null; })   : Promise.resolve(null),
        resUT   !== null ? fetchJson(dbFilePath(db, 'resources',  resUT))['catch'](function () { return null; })  : Promise.resolve(null),
        mnUT    !== null ? fetchJson(dbFilePath(db, 'manifest',   mnUT))['catch'](function () { return null; })   : Promise.resolve(null),
        cmUT    !== null ? fetchJson(dbFilePath(db, 'comms',      cmUT))['catch'](function () { return null; })   : Promise.resolve(null),
        fdUT    !== null ? fetchJson(dbFilePath(db, 'flightdata', fdUT))['catch'](function () { return null; })   : Promise.resolve(null),
        ptUT    !== null ? fetchJson(dbFilePath(db, 'ports',      ptUT))['catch'](function () { return null; })   : Promise.resolve(null),
        futCdUT  !== null ? fetchJson(dbFilePath(db, 'craftdata',  futCdUT))['catch'](function () { return null; })  : Promise.resolve(null),
        futResUT !== null ? fetchJson(dbFilePath(db, 'resources',  futResUT))['catch'](function () { return null; }) : Promise.resolve(null),
        futMnUT  !== null ? fetchJson(dbFilePath(db, 'manifest',   futMnUT))['catch'](function () { return null; })  : Promise.resolve(null),
        futCmUT  !== null ? fetchJson(dbFilePath(db, 'comms',      futCmUT))['catch'](function () { return null; })  : Promise.resolve(null),
        futFdUT  !== null ? fetchJson(dbFilePath(db, 'flightdata', futFdUT))['catch'](function () { return null; })  : Promise.resolve(null),
        futPtUT  !== null ? fetchJson(dbFilePath(db, 'ports',      futPtUT))['catch'](function () { return null; })  : Promise.resolve(null)
      ]).then(function (fetched) {
        var catalogEntry = null;
        for (var vi = 0; vi < vesselCatalog.length; vi++) {
          if (vesselCatalog[vi].DB === db) { catalogEntry = vesselCatalog[vi]; break; }
        }
        return {
          catalogEntry: catalogEntry,
          craftRecord:  fetched[0],
          resRecord:    fetched[1],
          mnRecord:     fetched[2],
          cmRecord:     fetched[3],
          fdRecord:     fetched[4],
          ptRecord:     fetched[5],
          futCdRecord:  fetched[6],
          futResRecord: fetched[7],
          futMnRecord:  fetched[8],
          futCmRecord:  fetched[9],
          futFdRecord:  fetched[10],
          futPtRecord:  fetched[11]
        };
      });
    }).then(function (d) {
      // Resources: add NotNull — true if any non-UT field has a value.
      var resRecord = d.resRecord;
      if (resRecord) {
        var resNotNull = false;
        var resKeys = Object.keys(resRecord);
        for (var ri = 0; ri < resKeys.length; ri++) {
          var rk = resKeys[ri];
          if (rk !== 'UT' && resRecord[rk] !== null && resRecord[rk] !== undefined && resRecord[rk] !== '') {
            resNotNull = true; break;
          }
        }
        resRecord = Object.assign({}, resRecord, { NotNull: resNotNull });
      }

      // Comms: add NotNull — true if the Comms array is non-empty.
      var cmRecord = d.cmRecord;
      if (cmRecord) {
        var cmNotNull = !!(cmRecord.Comms && cmRecord.Comms.length > 0);
        cmRecord = Object.assign({}, cmRecord, { NotNull: cmNotNull });
      }

      // Future resources: add NotNull.
      var futResRecord = d.futResRecord;
      if (futResRecord) {
        var futResNotNull = false;
        var futResKeys = Object.keys(futResRecord);
        for (var fri = 0; fri < futResKeys.length; fri++) {
          var frk = futResKeys[fri];
          if (frk !== 'UT' && futResRecord[frk] !== null && futResRecord[frk] !== undefined && futResRecord[frk] !== '') {
            futResNotNull = true; break;
          }
        }
        futResRecord = Object.assign({}, futResRecord, { NotNull: futResNotNull });
      }

      // Future comms: add NotNull.
      var futCmRecord = d.futCmRecord;
      if (futCmRecord) {
        var futCmNotNull = !!(futCmRecord.Comms && futCmRecord.Comms.length > 0);
        futCmRecord = Object.assign({}, futCmRecord, { NotNull: futCmNotNull });
      }

      // Orbit (flightdata): normalize keys to strip spaces.
      var orbitRecord    = _normalizeKeys(d.fdRecord);
      var futOrbitRecord = _normalizeKeys(d.futFdRecord);

      _trackAndInvoke(label, callback, {
        type: 'vessel',
        id:   db,
        current: {
          CraftData: d.craftRecord ? { UT: d.craftRecord.UT } : { UT: 0 },
          Resources: resRecord     ? { UT: resRecord.UT }     : { UT: 0 },
          Manifest:  d.mnRecord    ? { UT: d.mnRecord.UT }    : { UT: 0 },
          Comms:     cmRecord      ? { UT: cmRecord.UT }      : { UT: 0 },
          Orbit:     orbitRecord   ? { UT: orbitRecord.UT }   : { UT: 0 },
          Ports:     d.ptRecord    ? { UT: d.ptRecord.UT }    : { UT: 0 }
        },
        future: {
          CraftData: d.futCdRecord  || null,
          Resources: futResRecord   || null,
          Manifest:  d.futMnRecord  || null,
          Comms:     futCmRecord    || null,
          Orbit:     futOrbitRecord || null,
          Ports:     d.futPtRecord  || null
        }
      }, data);
    })['catch'](function (err) {
      var idx = KSA_UI_STATE.dataLoadQueue.indexOf(label);
      if (idx > -1) KSA_UI_STATE.dataLoadQueue.splice(idx, 1);
      handleError(err, label, true);
    });
  }

  // ===========================================================================
  // EXPORTS
  // ===========================================================================

  return {
    // Core data utilities
    seekToUT:        seekToUT,
    getNextUT:       getNextUT,
    fetchJson:       fetchJson,
    _trackAndInvoke: _trackAndInvoke,
    // Index management
    loadIndex:       loadIndex,
    // Path helpers
    indexPath:       indexPath,
    dbFilePath:      dbFilePath,
    bulkFilePath:    bulkFilePath,
    catalogFilePath: catalogFilePath,
    flightFilePath:  flightFilePath,
    // Endpoint implementations
    fetchBodyData:         fetchBodyData,
    fetchPartsData:        fetchPartsData,
    fetchAscentData:       fetchAscentData,
    fetchMapData:          fetchMapData,
    fetchFltData:          fetchFltData,
    fetchMenuData:         fetchMenuData,
    fetchEventData:        fetchEventData,
    fetchCrewData:         fetchCrewData,
    fetchVesselOrbitData:  fetchVesselOrbitData,
    fetchVesselData:       fetchVesselData,
    fetchOpsData:          fetchOpsData
  };

}());
